     1â†’import type { Scope } from '@typescript-eslint/scope-manager';
     2â†’import type { TSESTree } from '@typescript-eslint/utils';
     3â†’import type { ReportFixFunction } from '@typescript-eslint/utils/ts-eslint';
     4â†’
     5â†’import { AST_NODE_TYPES, AST_TOKEN_TYPES } from '@typescript-eslint/utils';
     6â†’import * as tsutils from 'ts-api-utils';
     7â†’import * as ts from 'typescript';
     8â†’
     9â†’import {
    10â†’  createRule,
    11â†’  getConstrainedTypeAtLocation,
    12â†’  getContextualType,
    13â†’  getDeclaration,
    14â†’  getModifiers,
    15â†’  getParserServices,
    16â†’  isNullableType,
    17â†’  isTypeFlagSet,
    18â†’  nullThrows,
    19â†’  NullThrowsReasons,
    20â†’} from '../util';
    21â†’
    22â†’export type Options = [
    23â†’  {
    24â†’    checkLiteralConstAssertions?: boolean;
    25â†’    typesToIgnore?: string[];
    26â†’  },
    27â†’];
    28â†’export type MessageIds = 'contextuallyUnnecessary' | 'unnecessaryAssertion';
    29â†’
    30â†’export default createRule<Options, MessageIds>({
    31â†’  name: 'no-unnecessary-type-assertion',
    32â†’  meta: {
    33â†’    type: 'suggestion',
    34â†’    docs: {
    35â†’      description:
    36â†’        'Disallow type assertions that do not change the type of an expression',
    37â†’      recommended: 'recommended',
    38â†’      requiresTypeChecking: true,
    39â†’    },
    40â†’    fixable: 'code',
    41â†’    messages: {
    42â†’      contextuallyUnnecessary:
    43â†’        'This assertion is unnecessary since the receiver accepts the original type of the expression.',
    44â†’      unnecessaryAssertion:
    45â†’        'This assertion is unnecessary since it does not change the type of the expression.',
    46â†’    },
    47â†’    schema: [
    48â†’      {
    49â†’        type: 'object',
    50â†’        additionalProperties: false,
    51â†’        properties: {
    52â†’          checkLiteralConstAssertions: {
    53â†’            type: 'boolean',
    54â†’            description: 'Whether to check literal const assertions.',
    55â†’          },
    56â†’          typesToIgnore: {
    57â†’            type: 'array',
    58â†’            description: 'A list of type names to ignore.',
    59â†’            items: {
    60â†’              type: 'string',
    61â†’            },
    62â†’          },
    63â†’        },
    64â†’      },
    65â†’    ],
    66â†’  },
    67â†’  defaultOptions: [{}],
    68â†’  create(context, [options]) {
    69â†’    const services = getParserServices(context);
    70â†’    const checker = services.program.getTypeChecker();
    71â†’    const compilerOptions = services.program.getCompilerOptions();
    72â†’
    73â†’    /**
    74â†’     * Returns true if there's a chance the variable has been used before a value has been assigned to it
    75â†’     */
    76â†’    function isPossiblyUsedBeforeAssigned(node: TSESTree.Expression): boolean {
    77â†’      const declaration = getDeclaration(services, node);
    78â†’      if (!declaration) {
    79â†’        // don't know what the declaration is for some reason, so just assume the worst
    80â†’        return true;
    81â†’      }
    82â†’
    83â†’      if (
    84â†’        // non-strict mode doesn't care about used before assigned errors
    85â†’        tsutils.isStrictCompilerOptionEnabled(
    86â†’          compilerOptions,
    87â†’          'strictNullChecks',
    88â†’        ) &&
    89â†’        // ignore class properties as they are compile time guarded
    90â†’        // also ignore function arguments as they can't be used before defined
    91â†’        ts.isVariableDeclaration(declaration)
    92â†’      ) {
    93â†’        // For var declarations, we need to check whether the node
    94â†’        // is actually in a descendant of its declaration or not. If not,
    95â†’        // it may be used before defined.
    96â†’
    97â†’        // eg
    98â†’        // if (Math.random() < 0.5) {
    99â†’        //     var x: number  = 2;
   100â†’        // } else {
   101â†’        //     x!.toFixed();
   102â†’        // }
   103â†’        if (
   104â†’          ts.isVariableDeclarationList(declaration.parent) &&
   105â†’          // var
   106â†’          declaration.parent.flags === ts.NodeFlags.None &&
   107â†’          // If they are not in the same file it will not exist.
   108â†’          // This situation must not occur using before defined.
   109â†’          services.tsNodeToESTreeNodeMap.has(declaration)
   110â†’        ) {
   111â†’          const declaratorNode: TSESTree.VariableDeclaration =
   112â†’            services.tsNodeToESTreeNodeMap.get(declaration);
   113â†’          const scope = context.sourceCode.getScope(node);
   114â†’          const declaratorScope = context.sourceCode.getScope(declaratorNode);
   115â†’          let parentScope: Scope | null = declaratorScope;
   116â†’          while ((parentScope = parentScope.upper)) {
   117â†’            if (parentScope === scope) {
   118â†’              return true;
   119â†’            }
   120â†’          }
   121â†’        }
   122â†’
   123â†’        if (
   124â†’          // is it `const x!: number`
   125â†’          declaration.initializer == null &&
   126â†’          declaration.exclamationToken == null &&
   127â†’          declaration.type != null
   128â†’        ) {
   129â†’          // check if the defined variable type has changed since assignment
   130â†’          const declarationType = checker.getTypeFromTypeNode(declaration.type);
   131â†’          const type = getConstrainedTypeAtLocation(services, node);
   132â†’          if (
   133â†’            declarationType === type &&
   134â†’            // `declare`s are never narrowed, so never skip them
   135â†’            !(
   136â†’              ts.isVariableDeclarationList(declaration.parent) &&
   137â†’              ts.isVariableStatement(declaration.parent.parent) &&
   138â†’              tsutils.includesModifier(
   139â†’                getModifiers(declaration.parent.parent),
   140â†’                ts.SyntaxKind.DeclareKeyword,
   141â†’              )
   142â†’            )
   143â†’          ) {
   144â†’            // possibly used before assigned, so just skip it
   145â†’            // better to false negative and skip it, than false positive and fix to compile erroring code
   146â†’            //
   147â†’            // no better way to figure this out right now
   148â†’            // https://github.com/Microsoft/TypeScript/issues/31124
   149â†’            return true;
   150â†’          }
   151â†’        }
   152â†’      }
   153â†’      return false;
   154â†’    }
   155â†’
   156â†’    function isConstAssertion(node: TSESTree.TypeNode): boolean {
   157â†’      return (
   158â†’        node.type === AST_NODE_TYPES.TSTypeReference &&
   159â†’        node.typeName.type === AST_NODE_TYPES.Identifier &&
   160â†’        node.typeName.name === 'const'
   161â†’      );
   162â†’    }
   163â†’
   164â†’    function isTemplateLiteralWithExpressions(expression: TSESTree.Expression) {
   165â†’      return (
   166â†’        expression.type === AST_NODE_TYPES.TemplateLiteral &&
   167â†’        expression.expressions.length !== 0
   168â†’      );
   169â†’    }
   170â†’
   171â†’    function isImplicitlyNarrowedLiteralDeclaration({
   172â†’      expression,
   173â†’      parent,
   174â†’    }: TSESTree.TSAsExpression | TSESTree.TSTypeAssertion): boolean {
   175â†’      /**
   176â†’       * Even on `const` variable declarations, template literals with expressions can sometimes be widened without a type assertion.
   177â†’       * @see https://github.com/typescript-eslint/typescript-eslint/issues/8737
   178â†’       */
   179â†’      if (isTemplateLiteralWithExpressions(expression)) {
   180â†’        return false;
   181â†’      }
   182â†’
   183â†’      // eslint-disable-next-line @typescript-eslint/no-non-null-assertion
   184â†’      const maybeDeclarationNode = parent.parent!;
   185â†’
   186â†’      return (
   187â†’        (maybeDeclarationNode.type === AST_NODE_TYPES.VariableDeclaration &&
   188â†’          maybeDeclarationNode.kind === 'const') ||
   189â†’        (parent.type === AST_NODE_TYPES.PropertyDefinition && parent.readonly)
   190â†’      );
   191â†’    }
   192â†’
   193â†’    function isTypeUnchanged(uncast: ts.Type, cast: ts.Type): boolean {
   194â†’      if (uncast === cast) {
   195â†’        return true;
   196â†’      }
   197â†’
   198â†’      if (
   199â†’        isTypeFlagSet(uncast, ts.TypeFlags.Undefined) &&
   200â†’        isTypeFlagSet(cast, ts.TypeFlags.Undefined) &&
   201â†’        tsutils.isCompilerOptionEnabled(
   202â†’          compilerOptions,
   203â†’          'exactOptionalPropertyTypes',
   204â†’        )
   205â†’      ) {
   206â†’        const uncastParts = tsutils
   207â†’          .unionConstituents(uncast)
   208â†’          .filter(part => !isTypeFlagSet(part, ts.TypeFlags.Undefined));
   209â†’
   210â†’        const castParts = tsutils
   211â†’          .unionConstituents(cast)
   212â†’          .filter(part => !isTypeFlagSet(part, ts.TypeFlags.Undefined));
   213â†’
   214â†’        if (uncastParts.length !== castParts.length) {
   215â†’          return false;
   216â†’        }
   217â†’
   218â†’        const uncastPartsSet = new Set(uncastParts);
   219â†’        return castParts.every(part => uncastPartsSet.has(part));
   220â†’      }
   221â†’
   222â†’      return false;
   223â†’    }
   224â†’
   225â†’    function isTypeLiteral(type: ts.Type) {
   226â†’      return type.isLiteral() || tsutils.isBooleanLiteralType(type);
   227â†’    }
   228â†’
   229â†’    function isIIFE(
   230â†’      expression: TSESTree.Expression,
   231â†’    ): expression is TSESTree.CallExpression & {
   232â†’      callee: TSESTree.ArrowFunctionExpression | TSESTree.FunctionExpression;
   233â†’    } {
   234â†’      return (
   235â†’        expression.type === AST_NODE_TYPES.CallExpression &&
   236â†’        (expression.callee.type === AST_NODE_TYPES.ArrowFunctionExpression ||
   237â†’          expression.callee.type === AST_NODE_TYPES.FunctionExpression)
   238â†’      );
   239â†’    }
   240â†’
   241â†’    function getUncastType(
   242â†’      node: TSESTree.TSAsExpression | TSESTree.TSTypeAssertion,
   243â†’    ): ts.Type {
   244â†’      // Special handling for IIFE: extract the function's return type
   245â†’      if (isIIFE(node.expression)) {
   246â†’        const callee = node.expression.callee;
   247â†’        const functionType = services.getTypeAtLocation(callee);
   248â†’        const signatures = functionType.getCallSignatures();
   249â†’
   250â†’        if (signatures.length > 0) {
   251â†’          const returnType = checker.getReturnTypeOfSignature(signatures[0]);
   252â†’
   253â†’          // If the function has no explicit return type annotation and returns undefined,
   254â†’          // treat it as void (TypeScript infers () => {} as () => undefined, but it should be void)
   255â†’          if (
   256â†’            callee.returnType == null &&
   257â†’            isTypeFlagSet(returnType, ts.TypeFlags.Undefined)
   258â†’          ) {
   259â†’            return checker.getVoidType();
   260â†’          }
   261â†’
   262â†’          return returnType;
   263â†’        }
   264â†’      }
   265â†’
   266â†’      return services.getTypeAtLocation(node.expression);
   267â†’    }
   268â†’
   269â†’    return {
   270â†’      'TSAsExpression, TSTypeAssertion'(
   271â†’        node: TSESTree.TSAsExpression | TSESTree.TSTypeAssertion,
   272â†’      ): void {
   273â†’        if (
   274â†’          options.typesToIgnore?.includes(
   275â†’            context.sourceCode.getText(node.typeAnnotation),
   276â†’          )
   277â†’        ) {
   278â†’          return;
   279â†’        }
   280â†’
   281â†’        const castType = services.getTypeAtLocation(node);
   282â†’        const castTypeIsLiteral = isTypeLiteral(castType);
   283â†’        const typeAnnotationIsConstAssertion = isConstAssertion(
   284â†’          node.typeAnnotation,
   285â†’        );
   286â†’
   287â†’        if (
   288â†’          !options.checkLiteralConstAssertions &&
   289â†’          castTypeIsLiteral &&
   290â†’          typeAnnotationIsConstAssertion
   291â†’        ) {
   292â†’          return;
   293â†’        }
   294â†’
   295â†’        const uncastType = getUncastType(node);
   296â†’
   297â†’        const typeIsUnchanged = isTypeUnchanged(uncastType, castType);
   298â†’        const wouldSameTypeBeInferred = castTypeIsLiteral
   299â†’          ? isImplicitlyNarrowedLiteralDeclaration(node)
   300â†’          : !typeAnnotationIsConstAssertion;
   301â†’
   302â†’        if (typeIsUnchanged && wouldSameTypeBeInferred) {
   303â†’          context.report({
   304â†’            node,
   305â†’            messageId: 'unnecessaryAssertion',
   306â†’            fix(fixer) {
   307â†’              if (node.type === AST_NODE_TYPES.TSTypeAssertion) {
   308â†’                const openingAngleBracket = nullThrows(
   309â†’                  context.sourceCode.getTokenBefore(
   310â†’                    node.typeAnnotation,
   311â†’                    token =>
   312â†’                      token.type === AST_TOKEN_TYPES.Punctuator &&
   313â†’                      token.value === '<',
   314â†’                  ),
   315â†’                  NullThrowsReasons.MissingToken('<', 'type annotation'),
   316â†’                );
   317â†’                const closingAngleBracket = nullThrows(
   318â†’                  context.sourceCode.getTokenAfter(
   319â†’                    node.typeAnnotation,
   320â†’                    token =>
   321â†’                      token.type === AST_TOKEN_TYPES.Punctuator &&
   322â†’                      token.value === '>',
   323â†’                  ),
   324â†’                  NullThrowsReasons.MissingToken('>', 'type annotation'),
   325â†’                );
   326â†’
   327â†’                // < ( number ) > ( 3 + 5 )
   328â†’                // ^---remove---^
   329â†’                return fixer.removeRange([
   330â†’                  openingAngleBracket.range[0],
   331â†’                  closingAngleBracket.range[1],
   332â†’                ]);
   333â†’              }
   334â†’              // `as` is always present in TSAsExpression
   335â†’              const asToken = nullThrows(
   336â†’                context.sourceCode.getTokenAfter(
   337â†’                  node.expression,
   338â†’                  token =>
   339â†’                    token.type === AST_TOKEN_TYPES.Identifier &&
   340â†’                    token.value === 'as',
   341â†’                ),
   342â†’                NullThrowsReasons.MissingToken('>', 'type annotation'),
   343â†’              );
   344â†’              const tokenBeforeAs = nullThrows(
   345â†’                context.sourceCode.getTokenBefore(asToken, {
   346â†’                  includeComments: true,
   347â†’                }),
   348â†’                NullThrowsReasons.MissingToken('comment', 'as'),
   349â†’              );
   350â†’
   351â†’              // ( 3 + 5 )  as  number
   352â†’              //          ^--remove--^
   353â†’              return fixer.removeRange([tokenBeforeAs.range[1], node.range[1]]);
   354â†’            },
   355â†’          });
   356â†’        }
   357â†’
   358â†’        // TODO - add contextually unnecessary check for this
   359â†’      },
   360â†’      TSNonNullExpression(node): void {
   361â†’        const removeExclamationFix: ReportFixFunction = fixer => {
   362â†’          const exclamationToken = nullThrows(
   363â†’            context.sourceCode.getLastToken(node, token => token.value === '!'),
   364â†’            NullThrowsReasons.MissingToken(
   365â†’              'exclamation mark',
   366â†’              'non-null assertion',
   367â†’            ),
   368â†’          );
   369â†’
   370â†’          return fixer.removeRange(exclamationToken.range);
   371â†’        };
   372â†’
   373â†’        if (
   374â†’          node.parent.type === AST_NODE_TYPES.AssignmentExpression &&
   375â†’          node.parent.operator === '='
   376â†’        ) {
   377â†’          if (node.parent.left === node) {
   378â†’            context.report({
   379â†’              node,
   380â†’              messageId: 'contextuallyUnnecessary',
   381â†’              fix: removeExclamationFix,
   382â†’            });
   383â†’          }
   384â†’          // for all other = assignments we ignore non-null checks
   385â†’          // this is because non-null assertions can change the type-flow of the code
   386â†’          // so whilst they might be unnecessary for the assignment - they are necessary
   387â†’          // for following code
   388â†’          return;
   389â†’        }
   390â†’
   391â†’        const originalNode = services.esTreeNodeToTSNodeMap.get(node);
   392â†’
   393â†’        const constrainedType = getConstrainedTypeAtLocation(
   394â†’          services,
   395â†’          node.expression,
   396â†’        );
   397â†’        const actualType = services.getTypeAtLocation(node.expression);
   398â†’
   399â†’        // Check both the constrained type and the actual type.
   400â†’        // If either is nullable, we should not report the assertion as unnecessary.
   401â†’        // This handles cases like generic constraints with `any` where the
   402â†’        // constrained type is `any` (nullable) but the actual type might be
   403â†’        // a type parameter that TypeScript treats nominally.
   404â†’        // See: https://github.com/typescript-eslint/typescript-eslint/issues/11559
   405â†’        const constrainedTypeIsNullable = isNullableType(constrainedType);
   406â†’        const actualTypeIsNullable = isNullableType(actualType);
   407â†’
   408â†’        if (!constrainedTypeIsNullable && !actualTypeIsNullable) {
   409â†’          if (
   410â†’            node.expression.type === AST_NODE_TYPES.Identifier &&
   411â†’            isPossiblyUsedBeforeAssigned(node.expression)
   412â†’          ) {
   413â†’            return;
   414â†’          }
   415â†’
   416â†’          context.report({
   417â†’            node,
   418â†’            messageId: 'unnecessaryAssertion',
   419â†’            fix: removeExclamationFix,
   420â†’          });
   421â†’        } else {
   422â†’          // we know it's a nullable type
   423â†’          // so figure out if the variable is used in a place that accepts nullable types
   424â†’
   425â†’          // If the constrained type differs from the actual type (e.g., when dealing
   426â†’          // with unresolved generic type parameters), we should not report the assertion
   427â†’          // as contextually unnecessary. TypeScript may still require the assertion
   428â†’          // even if the constraint is nullable (like `any`).
   429â†’          // See: https://github.com/typescript-eslint/typescript-eslint/issues/11559
   430â†’          if (constrainedType !== actualType) {
   431â†’            return;
   432â†’          }
   433â†’
   434â†’          const contextualType = getContextualType(checker, originalNode);
   435â†’          if (contextualType) {
   436â†’            if (
   437â†’              isTypeFlagSet(constrainedType, ts.TypeFlags.Unknown) &&
   438â†’              !isTypeFlagSet(contextualType, ts.TypeFlags.Unknown)
   439â†’            ) {
   440â†’              return;
   441â†’            }
   442â†’
   443â†’            // in strict mode you can't assign null to undefined, so we have to make sure that
   444â†’            // the two types share a nullable type
   445â†’            const typeIncludesUndefined = isTypeFlagSet(
   446â†’              constrainedType,
   447â†’              ts.TypeFlags.Undefined,
   448â†’            );
   449â†’            const typeIncludesNull = isTypeFlagSet(
   450â†’              constrainedType,
   451â†’              ts.TypeFlags.Null,
   452â†’            );
   453â†’            const typeIncludesVoid = isTypeFlagSet(
   454â†’              constrainedType,
   455â†’              ts.TypeFlags.Void,
   456â†’            );
   457â†’
   458â†’            const contextualTypeIncludesUndefined = isTypeFlagSet(
   459â†’              contextualType,
   460â†’              ts.TypeFlags.Undefined,
   461â†’            );
   462â†’            const contextualTypeIncludesNull = isTypeFlagSet(
   463â†’              contextualType,
   464â†’              ts.TypeFlags.Null,
   465â†’            );
   466â†’            const contextualTypeIncludesVoid = isTypeFlagSet(
   467â†’              contextualType,
   468â†’              ts.TypeFlags.Void,
   469â†’            );
   470â†’
   471â†’            // make sure that the parent accepts the same types
   472â†’            // i.e. assigning `string | null | undefined` to `string | undefined` is invalid
   473â†’            const isValidUndefined = typeIncludesUndefined
   474â†’              ? contextualTypeIncludesUndefined
   475â†’              : true;
   476â†’            const isValidNull = typeIncludesNull
   477â†’              ? contextualTypeIncludesNull
   478â†’              : true;
   479â†’            const isValidVoid = typeIncludesVoid
   480â†’              ? contextualTypeIncludesVoid
   481â†’              : true;
   482â†’
   483â†’            if (isValidUndefined && isValidNull && isValidVoid) {
   484â†’              context.report({
   485â†’                node,
   486â†’                messageId: 'contextuallyUnnecessary',
   487â†’                fix: removeExclamationFix,
   488â†’              });
   489â†’            }
   490â†’          }
   491â†’        }
   492â†’      },
   493â†’    };
   494â†’  },
   495â†’});
   496â†’

